import { useState, useEffect } from 'react';
import { MapPin } from 'lucide-react';
import { useCity } from '../context/CityContext';

export default function Countdown() {
    const { city } = useCity();
    const [timeLeft, setTimeLeft] = useState({ hours: '00', minutes: '00', seconds: '00' });
    const [hijriDate, setHijriDate] = useState('');
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let interval;
        setLoading(true);

        const fetchPrayerTimes = async () => {
            try {
                const res = await fetch(
                    `https://api.aladhan.com/v1/timingsByCity?city=${encodeURIComponent(city.name)}&country=${city.country}&method=2`
                );
                const data = await res.json();

                if (data?.data?.timings?.Maghrib) {
                    const [h, m] = data.data.timings.Maghrib.split(':');
                    const maghrib = new Date();
                    maghrib.setHours(parseInt(h, 10), parseInt(m, 10), 0, 0);
                    if (new Date() > maghrib) maghrib.setDate(maghrib.getDate() + 1);

                    // Hijri Date from API
                    const hj = data.data.date.hijri;
                    setHijriDate(`${hj.day} ${hj.month.en.toUpperCase()} ${hj.year}H`);

                    setLoading(false);
                    clearInterval(interval);
                    interval = setInterval(() => {
                        const diff = maghrib - new Date();
                        if (diff > 0) {
                            setTimeLeft({
                                hours: String(Math.floor(diff / (1000 * 60 * 60))).padStart(2, '0'),
                                minutes: String(Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60))).padStart(2, '0'),
                                seconds: String(Math.floor((diff % (1000 * 60)) / 1000)).padStart(2, '0'),
                            });
                        } else {
                            setTimeLeft({ hours: '00', minutes: '00', seconds: '00' });
                        }
                    }, 1000);
                }
            } catch (err) {
                console.error('Failed to fetch prayer times:', err);
                setLoading(false);
            }
        };

        fetchPrayerTimes();
        return () => clearInterval(interval);
    }, [city]);

    if (loading) return <div className="animate-pulse h-72 bg-[#122A2F] rounded-3xl mb-8"></div>;

    return (
        <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-[#122A2F] to-[#0A161E] border border-emerald-900/30 p-8 md:p-10 flex flex-col items-center mb-8 shadow-2xl">
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[600px] h-[300px] bg-emerald-500/10 blur-[100px] rounded-full pointer-events-none"></div>

            {/* Ramadan Date - Info Section */}
            <div className="absolute top-7 left-8 z-10 hidden sm:flex flex-col gap-0.5">
                <span className="text-[10px] font-medium text-emerald-500/40 tracking-[0.2em] uppercase">HIJRI CALENDAR</span>
                <span className="text-white/90 font-medium text-sm tracking-wide">{hijriDate}</span>
            </div>

            {/* Mobile-only date info */}
            <div className="z-10 sm:hidden flex flex-col items-center mb-4 gap-1">
                <span className="text-[8px] font-medium text-emerald-500/40 tracking-[0.2em] uppercase">HIJRI CALENDAR</span>
                <span className="text-white/80 font-medium text-xs tracking-wide">{hijriDate}</span>
            </div>

            {/* City Label — read-only, changed from Prayer Times page */}
            <div className="z-10 mb-6 flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 px-4 py-1.5 rounded-full text-xs font-bold tracking-wider">
                <MapPin className="w-3 h-3" />
                {city.name.toUpperCase()}, INDONESIA
            </div>

            <h2 className="z-10 text-2xl md:text-3xl lg:text-4xl font-bold text-white mb-8 md:mb-10 text-center leading-tight">
                Time until <span className="text-emerald-400">Maghrib</span> <br className="sm:hidden" /> (Iftar)
            </h2>

            {/* Boxes Layout */}
            <div className="flex items-center gap-3 md:gap-6">
                {[
                    { label: 'HOURS', value: timeLeft.hours },
                    { label: 'MINUTES', value: timeLeft.minutes },
                    { label: 'SECONDS', value: timeLeft.seconds, highlight: true },
                ].map(({ label, value, highlight }, i, arr) => (
                    <div key={label} className="flex flex-col items-center">
                        <div className={`bg-[#0b131c] w-16 h-16 sm:w-20 sm:h-20 md:w-32 md:h-32 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border relative overflow-hidden group ${highlight ? 'border-emerald-500/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' : 'border-white/5'}`}>
                            <div className={`absolute inset-0 transition-colors ${highlight ? 'bg-emerald-500/10 group-hover:bg-emerald-500/20' : 'bg-emerald-500/5 group-hover:bg-emerald-500/10'}`}></div>
                            <span className={`text-2xl sm:text-3xl md:text-6xl font-bold font-mono tracking-tighter shadow-sm ${highlight ? 'text-emerald-300' : 'text-emerald-400'}`}>{value}</span>
                        </div>
                        <span className="text-gray-500 text-[8px] md:text-xs font-bold tracking-widest mt-3 md:mt-4">{label}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}
